// Referencia cada nó pelo nome exato que aparece no seu canvas
const down         = $('Buscar os Alertas WAN Down').all().map(i => i.json);
const restored     = $('Buscar os Alertas WAN Restored').all().map(i => i.json);
const dispositivos = $('Get many rows').all().map(i => i.json);

// Mês atual para teste
const agora  = new Date();
const mesRef = agora.getMonth() === 0 ? 11 : agora.getMonth() - 1;
const anoRef = agora.getMonth() === 0 ? agora.getFullYear() - 1 : agora.getFullYear();

function parseHorario(str) {
  if (!str) return null;
  if (str.includes('T')) return new Date(str);
  const match = str.match(/(\d{2})\/(\d{2})\/(\d{2}),\s*(\d{2}):(\d{2}):(\d{2})/);
  if (!match) return null;
  const [_, dd, mm, yy, hh, mi, ss] = match;
  return new Date(`20${yy}-${mm}-${dd}T${hh}:${mi}:${ss}`);
}

function noMes(dateStr) {
  const d = parseHorario(dateStr);
  if (!d) return false;
  return d.getMonth() === mesRef && d.getFullYear() === anoRef;
}

const downFiltrado         = down.filter(r => noMes(r['Horario']));
const restoredFiltrado     = restored.filter(r => noMes(r['Horario']));
const dispositivosFiltrado = dispositivos.filter(r => noMes(r['Created On']));

return [{
  json: {
    down: downFiltrado,
    restored: restoredFiltrado,
    dispositivos: dispositivosFiltrado,
    mesRef,
    anoRef,
    _totais: {
      down: down.length,
      restored: restored.length,
      dispositivos: dispositivos.length
    }
  }
}];

const { down, restored, dispositivos, mesRef, anoRef } = $input.first().json;

function parseHorario(str) {
  if (!str) return null;
  if (str.includes('T')) return new Date(str);
  const match = str.match(/(\d{2})\/(\d{2})\/(\d{2}),\s*(\d{2}):(\d{2}):(\d{2})/);
  if (!match) return null;
  const [_, dd, mm, yy, hh, mi, ss] = match;
  return new Date(`20${yy}-${mm}-${dd}T${hh}:${mi}:${ss}`);
}

function formatarDuracao(ms) {
  if (!ms || ms <= 0) return '—';
  const h = Math.floor(ms / 3600000);
  const m = Math.floor((ms % 3600000) / 60000);
  return h > 0 ? `${h}h ${m}min` : `${m}min`;
}

// Cria índice de restored por Ticket para busca rápida
const restoredPorTicket = {};
for (const r of restored) {
  if (r['Ticket']) restoredPorTicket[String(r['Ticket'])] = r;
}

function encontrarRestored(evento) {
  const match = restoredPorTicket[String(evento['Ticket'])];
  if (match) return match;
  const queda = parseHorario(evento['Horario']);
  if (!queda) return null;
  const candidatos = restored
    .filter(r =>
      r['Dispositivos'] === evento['Dispositivos'] &&
      r['WAN'] === evento['WAN'] &&
      parseHorario(r['Horario']) > queda
    )
    .sort((a, b) => parseHorario(a['Horario']) - parseHorario(b['Horario']));
  return candidatos[0] || null;
}

// Monta estrutura: empresa → CGU → link → incidentes
const empresas = {};

for (const evento of down) {
  // Ignora status que não são quedas reais
  if (!['DOWN', 'FAILOVER'].includes(evento['Status'])) continue;

  const cliente = evento['Cliente'] || 'Sem Cliente';
  const cgu     = evento['Dispositivos'] || 'Sem Dispositivo';
  const link    = evento['WAN'] || 'WAN desconhecida';
  const isp     = evento['ISP'] || '';
  const queda   = parseHorario(evento['Horario']);
  const rest    = encontrarRestored(evento);
  const restauracao = rest ? parseHorario(rest['Horario']) : null;
  const duracao = (queda && restauracao && restauracao > queda)
    ? (restauracao - queda)
    : null;

  if (!empresas[cliente]) empresas[cliente] = {};
  if (!empresas[cliente][cgu]) empresas[cliente][cgu] = {};
  if (!empresas[cliente][cgu][link]) {
    empresas[cliente][cgu][link] = { isp, totalMs: 0, maiorMs: 0, incidentes: 0 };
  }

  empresas[cliente][cgu][link].incidentes += 1;
  if (duracao) {
    empresas[cliente][cgu][link].totalMs += duracao;
    if (duracao > empresas[cliente][cgu][link].maiorMs) {
      empresas[cliente][cgu][link].maiorMs = duracao;
    }
  }
}

// Formata resultado
const resultado = {};
for (const [empresa, cgus] of Object.entries(empresas)) {
  resultado[empresa] = {};
  for (const [cgu, links] of Object.entries(cgus)) {
    let totalCguMs = 0;
    const linksFormatados = {};
    for (const [link, dados] of Object.entries(links)) {
      totalCguMs += dados.totalMs;
      linksFormatados[link] = {
        isp: dados.isp,
        totalOffline: formatarDuracao(dados.totalMs),
        maiorOffline: formatarDuracao(dados.maiorMs),
        incidentes: dados.incidentes
      };
    }
    resultado[empresa][cgu] = {
      totalOffline: formatarDuracao(totalCguMs),
      links: linksFormatados
    };
  }
}

const meses = ['Janeiro','Fevereiro','Março','Abril','Maio','Junho',
                'Julho','Agosto','Setembro','Outubro','Novembro','Dezembro'];

return [{ json: { dados: resultado, mesNome: meses[mesRef], anoRef } }];
